import{e as c,u as l,j as e}from"./index-CqEpTYX5.js";import{c as o}from"./createLucideIcon-DOz51p8L.js";import{Z as u,G as d,A as y}from"./zap-DNYrKlKP.js";import{S as m,B as h}from"./shield-4f0EM0Js.js";import{S as a,m as p}from"./sparkles-DTM4VoWE.js";const g=[["path",{d:"M10 2v2",key:"7u0qdc"}],["path",{d:"M14 2v2",key:"6buw04"}],["path",{d:"M16 8a1 1 0 0 1 1 1v8a4 4 0 0 1-4 4H7a4 4 0 0 1-4-4V9a1 1 0 0 1 1-1h14a4 4 0 1 1 0 8h-1",key:"pwadti"}],["path",{d:"M6 2v2",key:"colzsn"}]],f=o("coffee",g);const v=[["path",{d:"M2 9.5a5.5 5.5 0 0 1 9.591-3.676.56.56 0 0 0 .818 0A5.49 5.49 0 0 1 22 9.5c0 2.29-1.5 4-3 5.5l-5.492 5.313a2 2 0 0 1-3 .019L5 15c-1.5-1.5-3-3.2-3-5.5",key:"mvr1a0"}]],w=o("heart",v);const b=[["path",{d:"M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2",key:"1yyitq"}],["path",{d:"M16 3.128a4 4 0 0 1 0 7.744",key:"16gr8j"}],["path",{d:"M22 21v-2a4 4 0 0 0-3-3.87",key:"kshegd"}],["circle",{cx:"9",cy:"7",r:"4",key:"nufk8"}]],n=o("users",b),M=()=>{const{pageId:i}=c(),s=l(),t={assessment:{title:"How We Understand You",content:'Our assessment goes far beyond a standard quiz. We utilize cognitive science principles to identify your unique learning cognitive architecture. By analyzing how you process information—whether through visual schemas, auditory narratives, or kinesthetic applications—we build a detailed "Neural Blueprint" of your learning style. This 5-minute interactive session also evaluates your current knowledge base and emotional readiness, allowing our AI to tailor every subsequent interaction to your specific needs.',icon:h},"learning-path":{title:"Your Adaptive Journey",content:'Forget rigid syllabi. Your learning path is a dynamic, living entity that breathes with you. Our "Neural Flow" algorithm adjusts your schedule in real-time based on your daily energy levels, performance, and retention rates. If you ace a concept, we accelerate. If you struggle, we pivot to a new teaching angle. We break down massive subjects into bite-sized "Micro-Mastery" nodes, turning a daunting mountain of coursework into a series of achievable, rewarding steps.',icon:a},resources:{title:"Curated Resource Vault",content:"Stop wasting hours sifting through low-quality tutorials. Our Resource Vault is an AI-curated library of the world's best educational content, vetted for accuracy and engagement. From high-definition video breakdowns and interactive 3D models to concise cheat sheets and expert-verified notes, everything you need is instantly accessible. We verify every source, so you can trust that you are learning from the reliable materials, perfectly matched to your syllabus.",icon:f},"about-us":{title:"Our Mission & Story",content:'We started My True Companion because we were tired of the "one-size-fits-all" education system that leaves so many brilliant minds behind. We are a diverse collective of educators, neuroscientists, and AI engineers united by a single purpose: to democratize personalized learning. We believe that burnout is a design flaw, not a user error. Our goal is to build a tool that acts not just as a tutor, but as a compassionate mentor that grows with you.',icon:w},careers:{title:"Join the Revolution",content:"We are building the future of education, and we need visionaries. At My True Companion, we value curiosity over credentials and impact over hours logged. We operate as a fully remote, asynchronous team that respects deep work and creative autonomy. If you are passionate about AI, pedagogy, or simply making the world a smarter place, we want to hear from you. We offer competitive equity, unlimited learning stipends, and the chance to change millions of lives.",icon:n},"privacy-policy":{title:"Your Privacy is Sacred",content:'In an age of data exploitation, we stand as a fortress for your privacy. We strictly adhere to a "User-First" data policy. Your learning data is encrypted end-to-end and is used solely to enhance your personal learning experience. We never sell, rent, or trade your personal information to third parties. You own your data completely—you can download or delete your entire history at any time with a single click. We are fully GDPR and CCPA compliant.',icon:m},twitter:{title:"Join the Conversation",content:`Follow @MyTrueCompanion for your daily dose of study motivation, neuroscience nuggets, and behind-the-scenes looks at our latest features. We host weekly "Study Space" threads where you can share your setup, ask questions to our engineering team, and connect with a global community of learners. It's not just a feed; it's a stream of inspiration to keep your academic momentum going.`,icon:d},discord:{title:"Your Global Study Group",content:`The journey is easier when you don't walk it alone. Our Discord server is a thriving 24/7 campus with over 50,000 active students. Join dedicated channels for your specific subjects, participate in guided "Pomodoro" study sessions with live lo-fi music, or just hang out in the "Break Room" to destress. Our community moderators and expert mentors are always online to help you unstuck specific problems or offer encouragement.`,icon:u},linkedin:{title:"Professional Updates",content:"Connect with us on LinkedIn for industry insights, partnership announcements, and professional growth opportunities. We regularly publish deep-dive articles on the intersection of AI and Education, case studies on student success, and opportunities for internships and ambassador programs. Use our network to build your own professional footprint while you learn.",icon:n}}[i]||{title:"Page Not Found",content:"The page you are looking for does not exist.",icon:a},r=t.icon;return e.jsxs("div",{className:"landing-container",style:{minHeight:"100vh",padding:"2rem"},children:[e.jsxs("div",{className:"bg-blobs",children:[e.jsx("div",{className:"bg-glow-1"}),e.jsx("div",{className:"bg-glow-2"})]}),e.jsxs("div",{style:{maxWidth:"800px",margin:"0 auto",position:"relative",zIndex:10},children:[e.jsxs("button",{onClick:()=>s("/"),className:"btn btn-outline",style:{marginBottom:"2rem",display:"flex",alignItems:"center",gap:"0.5rem"},children:[e.jsx(y,{size:20})," Back to Home"]}),e.jsxs(p.div,{initial:{opacity:0,y:20},animate:{opacity:1,y:0},transition:{duration:.5},className:"glass",style:{padding:"3rem",borderRadius:"24px"},children:[e.jsx("div",{style:{width:"80px",height:"80px",background:"rgba(139, 92, 246, 0.1)",borderRadius:"20px",display:"flex",alignItems:"center",justifyContent:"center",marginBottom:"2rem",color:"#a78bfa"},children:e.jsx(r,{size:40})}),e.jsx("h1",{className:"hero-headline",style:{fontSize:"2.5rem",marginBottom:"1.5rem"},children:t.title}),e.jsx("p",{className:"hero-subtext",style:{fontSize:"1.1rem",marginBottom:"0"},children:t.content})]})]})]})};export{M as default};
